/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwwNotasTerceiros-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&NfeNum.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "NºNF") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeNum EndIf
If not (&NfePedCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfePedCod EndIf
If not (&NfeCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Seq.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCod EndIf
If not (&NfeCliCod.IsEmpty() AND &NfeCliRaz.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Fornec.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCliCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&NfeCliRaz) EndIf
If not (&EmpCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "CodigoEmpresa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmpCod EndIf
If not (&NfeProTer.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Terceira") If Not &NfeProTer.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeProTer.EnumerationDescription() Endif EndIf
If not (&FilCod.IsEmpty() AND &NfeSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "F.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod If Not &NfeSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = &NfeSts.EnumerationDescription() Endif EndIf
If not (&NfeDtaFat.IsEmpty() AND &NfeDtaFat_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Entrada") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &NfeDtaFat WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &NfeDtaFat_To EndIf
If not (&NfeDtaEms.IsEmpty() AND &NfeDtaEms_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Em.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &NfeDtaEms WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &NfeDtaEms_To EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Filial" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Nº NF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Entrada" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "#" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Razão/Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Valor NF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = "Tipo Lcto."
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (NfeNum) when &OrderedBy = 1 order FilCod when &OrderedBy = 2 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 2 AND &OrderedDsc = True order NfeCod when &OrderedBy = 3 AND &OrderedDsc = False order (NfeCod) when &OrderedBy = 3 AND &OrderedDsc = True order NfeNum when &OrderedBy = 4 AND &OrderedDsc = False order (NfeNum) when &OrderedBy = 4 AND &OrderedDsc = True order NfePedCod when &OrderedBy = 5 AND &OrderedDsc = False order (NfePedCod) when &OrderedBy = 5 AND &OrderedDsc = True order NfeDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (NfeDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order NfeDtaFat when &OrderedBy = 7 AND &OrderedDsc = False order (NfeDtaFat) when &OrderedBy = 7 AND &OrderedDsc = True order NfeCliCod when &OrderedBy = 8 AND &OrderedDsc = False order (NfeCliCod) when &OrderedBy = 8 AND &OrderedDsc = True order NfeVlrTot when &OrderedBy = 9 AND &OrderedDsc = False order (NfeVlrTot) when &OrderedBy = 9 AND &OrderedDsc = True order NfeSts when &OrderedBy = 10 AND &OrderedDsc = False order (NfeSts) when &OrderedBy = 10 AND &OrderedDsc = True order NfeEntSai when &OrderedBy = 11 AND &OrderedDsc = False order (NfeEntSai) when &OrderedBy = 11 AND &OrderedDsc = True
using DSwwNotasTerceiros(&NfeNum, &NfePedCod, &NfeCod, &NfeCliCod, &NfeCliRaz, &EmpCod , &NfeProTer, &FilCod, &NfeSts, &NfeDtaFat, &NfeDtaFat_To, &NfeDtaEms , &NfeDtaEms_To)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = FilCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = NfeCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = NfeNum &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = NfePedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = NfeDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = NfeDtaFat &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Number = NfeCliCod if NfeCliRaz.Length() > 40 &gridNfeCliRaz = substr(upper(NfeCliRaz),1,37) + '...' Else &gridNfeCliRaz = NfeCliRaz EndIF &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = WWP_Export_SecureText(&GridNfeCliRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Number = NfeVlrTot &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = NfeSts.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = NfeEntSai.EnumerationDescription()
&gridNfeLctNom = trim(str(NfeLctCod)) + '-'+ Substr(NfeLctNom, 1, 15) &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = WWP_Export_SecureText(&gridNfeLctNom)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwNotasTerceirosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwNotasTerceirosGridState")) Else &GridState.FromXml(&Session.Get(!"wwNotasTerceirosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"NFENUM" &NfeNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPEDCOD" &NfePedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECOD" &NfeCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECLICOD" &NfeCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECLIRAZ" &NfeCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPROTER" &NfeProTer.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFESTS" &NfeSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEDTAFAT" &NfeDtaFat.FromString(&GridStateFilterValue.Value) &NfeDtaFat_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"NFEDTAEMS" &NfeDtaEms.FromString(&GridStateFilterValue.Value) &NfeDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

